// ─── Drag Reorder Utility ───
// Makes any list of elements reorderable via HTML5 drag-and-drop.
// Usage: spread dragProps(visualIndex) on each draggable element, render items via order array.
function useDragReorder(length) {
  const [order, setOrder] = useState(() => Array.from({ length }, (_, i) => i));
  const dragFrom = useRef(null);
  // Reset if length changes
  useEffect(() => { setOrder(prev => prev.length === length ? prev : Array.from({ length }, (_, i) => i)); }, [length]);
  const dragProps = (vi) => ({
    draggable: true,
    onDragStart: (e) => { dragFrom.current = vi; e.dataTransfer.effectAllowed = "move"; e.dataTransfer.setData("text/plain", ""); },
    onDragOver: (e) => e.preventDefault(),
    onDrop: (e) => {
      e.preventDefault();
      const from = dragFrom.current;
      if (from === null || from === vi) return;
      setOrder(prev => { const n = [...prev]; const [r] = n.splice(from, 1); n.splice(vi, 0, r); return n; });
      dragFrom.current = null;
    },
    style: { cursor: "grab" }
  });
  return { order, dragProps, setOrder };
}

// ─── Card Arrange Utility ───
// Drag-handle rearranging for dashboard cards, persisted per browser. Order is stored as section
// KEYS (not indexes) so a saved layout survives cards being added/removed in later versions.
// The wrapper is only draggable while its handle is held (armed) — clicks, text selection and
// inputs inside the card keep working normally.
function useCardArrange(keys, storageKey) {
  const [order, setOrder] = useState(() => {
    try {
      const saved = JSON.parse(localStorage.getItem(storageKey) || "[]");
      const valid = saved.filter(k => keys.includes(k));
      return valid.length ? [...valid, ...keys.filter(k => !valid.includes(k))] : keys;
    } catch { return keys; }
  });
  const [armed, setArmed] = useState(null);
  const dragFrom = useRef(null);
  const wrapProps = (vi) => ({
    draggable: armed === vi,
    onDragStart: (e) => {
      if (armed !== vi) { e.preventDefault(); return; }
      dragFrom.current = vi; e.dataTransfer.effectAllowed = "move";
      try { e.dataTransfer.setData("text/plain", ""); } catch {}
    },
    onDragOver: (e) => e.preventDefault(),
    onDrop: (e) => {
      e.preventDefault();
      const from = dragFrom.current;
      if (from == null || from === vi) return;
      setOrder(prev => { const n = [...prev]; const [r] = n.splice(from, 1); n.splice(vi, 0, r); try { localStorage.setItem(storageKey, JSON.stringify(n)); } catch {} return n; });
      dragFrom.current = null;
    },
    onDragEnd: () => { setArmed(null); dragFrom.current = null; },
  });
  const handleProps = (vi) => ({
    onMouseDown: () => setArmed(vi),
    onMouseUp: () => setArmed(null),
    title: "Drag to rearrange — your layout is saved to this browser",
  });
  return { order, wrapProps, handleProps, armed };
}

// ─── What's New — changelog the user can refer to (button in the top nav, modal of update notes).
// Add new entries to the TOP of WHATS_NEW as features ship.
// ── PLAYBOOK TRACKER ─────────────────────────────────────────────────────────
// Define a model playbook as measurable TARGETS, then track live adherence from the
// journal: each metric shows its live value vs your target with an ON TRACK / DEVIATING
// verdict. v1 ships the "Derisk fast · hunt homeruns" preset: cut losers to near-nothing
// quickly, accept a modest win rate, and let a handful of huge winners carry the P&L.
// Targets persist per-user in localStorage; metrics recompute live from closed trades.
const PLAYBOOK_PRESET = {
  name: "Playbook design",
  targets: { avgLoss: 5, payoff: 2, homerunShare: 50, winRate: 30 },
};
function PlaybookTracker({ trades, uid, setPage }) {
  const KEY = `viv-playbook-${uid || "anon"}-v1`;
  const [pb, setPb] = useState(() => { try { const s = JSON.parse(localStorage.getItem(KEY) || "null"); return s && s.targets ? { ...PLAYBOOK_PRESET, ...s, targets: { ...PLAYBOOK_PRESET.targets, ...s.targets } } : PLAYBOOK_PRESET; } catch { return PLAYBOOK_PRESET; } });
  useEffect(() => { try { localStorage.setItem(KEY, JSON.stringify(pb)); } catch { /* quota */ } }, [pb, KEY]);
  const m = useMemo(() => {
    const closed = trades.filter(t => t.exit);
    const wins = closed.filter(t => (Number(t.plPct) || 0) > 0);
    const losses = closed.filter(t => (Number(t.plPct) || 0) <= 0);
    const mean = (a) => a.length ? a.reduce((s, v) => s + v, 0) / a.length : null;
    const avgLoss = losses.length ? Math.abs(mean(losses.map(t => Number(t.plPct) || 0))) : null;
    const worstLoss = losses.length ? Math.max(...losses.map(t => Math.abs(Number(t.plPct) || 0))) : null;
    const avgWin = wins.length ? mean(wins.map(t => Number(t.plPct) || 0)) : null;
    const payoff = avgWin != null && avgLoss ? avgWin / avgLoss : null;
    const winRate = closed.length ? wins.length / closed.length * 100 : null;
    const gross = wins.reduce((s, t) => s + Math.max(0, Number(t.plDollar) || 0), 0);
    const topN = Math.max(1, Math.ceil(wins.length * 0.1));
    const top = wins.slice().sort((a, b) => (Number(b.plDollar) || 0) - (Number(a.plDollar) || 0)).slice(0, topN);
    const homerunShare = gross > 0 ? top.reduce((s, t) => s + Math.max(0, Number(t.plDollar) || 0), 0) / gross * 100 : null;
    // R-based variants — used when the design was built in R-multiples (members size by R).
    // Trades with no recorded R (no stop) are EXCLUDED from R rows and counted, never guessed.
    const rOf = (t) => { const v = Number(t.rMult); return t.rMult != null && isFinite(v) ? v : null; };
    const winRs = wins.map(rOf).filter(v => v != null);
    const lossRs = losses.map(rOf).filter(v => v != null).map(Math.abs);
    const avgLossR = lossRs.length ? mean(lossRs) : null;
    const avgWinR = winRs.length ? mean(winRs) : null;
    const noR = closed.filter(t => rOf(t) == null).length;
    return { n: closed.length, avgLoss, worstLoss, payoff, winRate, homerunShare, topN: wins.length ? topN : 0, avgWin,
      winPcts: wins.map(t => Number(t.plPct) || 0), winRs, lossRs, lossPcts: losses.map(t => Math.abs(Number(t.plPct) || 0)),
      avgLossR, avgWinR, payoffR: avgWinR != null && avgLossR ? avgWinR / avgLossR : null, noR };
  }, [trades]);
  // ── DESIGN PROGRESS — pace vs the design's structure (trade count + winner tiers). This is what
  // catches "all ratios green but the homeruns aren't happening": each tier shows how many winners
  // of that size the design expects BY NOW (pro-rated) vs how many actually landed.
  const pace = useMemo(() => {
    const d = pb.design;
    if (!d || !d.total || !Array.isArray(d.tiers) || !d.tiers.length) return null;
    const frac = Math.min(1, m.n / d.total);
    // Winner sizes measured in the design's OWN unit: R-multiple designs band on each win's R,
    // % designs band on plPct — never mixed.
    const unitR = d.unit === "r";
    const winSizes = unitR ? m.winRs : m.winPcts;
    const tiers = d.tiers.slice().sort((a, b) => b.gain - a.gain).map((t, i, arr) => {
      const hi = i === 0 ? Infinity : arr[i - 1].gain;              // tier band: [gain, next-bigger tier)
      const actual = winSizes.filter(p => p >= t.gain && p < hi).length;
      const expectedNow = t.count * frac;
      // Compare against the UNROUNDED expectation (Valen 2026-07-11): flooring let a 1-planned
      // homerun tier read "0 due → ON PACE" for half the cycle with nothing landed. 0 landed vs
      // 0.5 due is behind — the ladder must say so.
      return { gain: t.gain, planned: t.count, actual, expectedNow, ok: actual >= expectedNow };
    });
    return { total: d.total, taken: m.n, remaining: Math.max(0, d.total - m.n), frac, tiers, suffix: unitR ? "R" : "%" };
  }, [pb.design, m]);
  const [more, setMore] = useState(false);
  const [hov, setHov] = useState(null); // hovered trade index on the projection chart (0..100)
  const [roll, setRoll] = useState(1);  // MC seed — ↻ rolls another equally-likely future
  // Arrived via the simulator's "Compare stats" button → scroll here and open the comparison.
  useEffect(() => {
    try {
      if (sessionStorage.getItem("viv-goto-playbook")) {
        sessionStorage.removeItem("viv-goto-playbook");
        setMore(true);
        setTimeout(() => document.getElementById("playbook-tracker")?.scrollIntoView({ behavior: "smooth", block: "start" }), 350);
      }
    } catch { /* private mode */ }
  }, []);
  // Feedback loop: the playbook AS DESIGNED (targets) vs the book AS TRADED (actuals), each
  // projected forward — expectancy per trade compounded over the next 100 trades at simSize% risk deployed.
  const proj = useMemo(() => {
    const t = pb.targets;
    const unitR = pb.design?.unit === "r"; // R design: expectancy in R, size = % of equity risked/trade
    const size = Number(pb.simSize) > 0 ? Number(pb.simSize) : (unitR ? 0.5 : 15);
    const evOf = (wr, avgWin, avgLoss) => (wr == null || avgWin == null || avgLoss == null) ? null : (wr / 100) * avgWin - (1 - wr / 100) * avgLoss;
    const evSim = evOf(Number(t.winRate), Number(t.payoff) * Number(t.avgLoss), Number(t.avgLoss));
    const evAct = unitR ? evOf(m.winRate, m.avgWinR, m.avgLossR) : evOf(m.winRate, m.avgWin, m.avgLoss);
    // Per-trade growth: % design → size% × ev%; R design → risk% × evR (ev already in R units)
    const mult = (ev) => ev == null ? null : Math.pow(1 + (size / 100) * (unitR ? ev : ev / 100), 100);
    return { size, unitR, suffix: unitR ? "R" : "%", sizeLabel: unitR ? "% risk per trade" : "% position size", evSim, evAct, multSim: mult(evSim), multAct: mult(evAct) };
  }, [pb, m]);
  // ── Scoreboard: YOUR DESIGN vs LIVE, one row per metric. Pass/fail compares with half a
  // display-unit of tolerance so a live value that ROUNDS to the target (44.36% shown as 44.4%
  // against a 44.4% target) can't print a phantom MISS.
  const winsN = m.winPcts.length;
  const desWinRate = pb.design && pb.design.total ? (pb.design.winners / pb.design.total) * 100 : Number(pb.targets.winRate);
  const pass = (v, dir, tgt, tol = 0.05) => (v == null || !Number.isFinite(tgt)) ? null : (dir === "lte" ? v <= tgt + tol : v >= tgt - tol);
  const tg = pb.targets;
  // Score in the design's OWN unit: an R-multiple design compares R-based live stats (trades
  // without a recorded R are excluded and counted); a % design compares plPct-based stats.
  const uR = pb.design?.unit === "r";
  const liveAvgLoss = uR ? m.avgLossR : m.avgLoss;
  const livePayoff = uR ? m.payoffR : m.payoff;
  const ROWS = [
    { k: "winRate", label: "Winners · win rate", tip: "How many of your closed trades finished positive, against the share the design plans for. A homerun playbook survives a modest win rate — but not below the one you designed the math on.", design: pb.design && pb.design.total ? `${pb.design.winners} of ${pb.design.total} · ${desWinRate.toFixed(1)}%` : `≥ ${tg.winRate}%`, live: m.n ? `${winsN} of ${m.n} · ${m.winRate.toFixed(1)}%` : null, ok: pass(m.winRate, "gte", desWinRate) },
    { k: "avgLoss", label: "Average loss", tip: uR ? "Mean size of your losing trades in R — how much of one risk unit the typical loser actually costs. 1R = a full stop-out; a 3-stop structure designs for 0.67R." : "Mean size of your losing trades. The playbook's core discipline: derisk fast so the average loss stays tiny.", design: `≤ ${tg.avgLoss}${uR ? "R" : "%"}`, live: liveAvgLoss == null ? null : liveAvgLoss.toFixed(2) + (uR ? "R" : "%"), ok: pass(liveAvgLoss, "lte", Number(tg.avgLoss), uR ? 0.005 : 0.05) },
    { k: "payoff", label: "Avg win ÷ avg loss", tip: "The PAYOFF ratio — how much bigger the average win is than the average loss" + (uR ? ", measured in R (each trade scaled by its own risk; trades without a recorded R excluded)" : "") + ". NOT the same as Profit factor in Key metrics: payoff compares average sizes and ignores how often you win; profit factor divides TOTAL $ won by TOTAL $ lost, so frequency is baked in. A low-win-rate homerun system needs payoff comfortably above 2.", design: `≥ ${tg.payoff}×`, live: livePayoff == null ? null : livePayoff.toFixed(2) + "×", ok: pass(livePayoff, "gte", Number(tg.payoff), 0.005) },
    { k: "homerunShare", label: `Homerun share (top ${m.topN || 1} win${m.topN === 1 ? "" : "s"})`, tip: "Share of total gross profit that came from your biggest ~10% of winners. High = a few big trades carry the book, exactly as designed.", design: `≥ ${tg.homerunShare}%`, live: m.homerunShare == null ? null : m.homerunShare.toFixed(1) + "%", ok: pass(m.homerunShare, "gte", Number(tg.homerunShare)) },
  ];
  // ── ONE verdict — reconciled across the card's TWO judges (Valen 2026-07-12): the ratio checks
  // + expectancy measure the EDGE (outcome per trade); the winner ladder measures the SHAPE (are
  // the big winners the design counts on actually landing). A higher win rate + smaller losses can
  // carry the edge ahead while the tail runs behind — one label must tell that whole story, never
  // a red banner above a green "trading ahead" strip.
  const ratioFails = ROWS.filter(r => r.ok === false).map(r => r.label.split(" (")[0].toLowerCase());
  const tiersBehind = pace ? pace.tiers.filter(x => !x.ok) : [];
  const failList = [...ratioFails, ...tiersBehind.map(x => `+${x.gain}${pace.suffix}+ winners behind pace`)];
  const checksN = ROWS.filter(r => r.ok != null).length + (pace ? pace.tiers.length : 0);
  const edgeAhead = proj.evSim != null && proj.evAct != null && proj.evAct >= proj.evSim;
  const fmtEv = (v) => (v >= 0 ? "+" : "") + v.toFixed(2) + proj.suffix;
  const verdict = failList.length === 0
    ? { word: "ON TRACK", col: "var(--green)", bd: "rgba(34,197,94,0.35)", bg: "rgba(34,197,94,0.07)", why: `all ${checksN} checks passing` }
    : (ratioFails.length === 0 && tiersBehind.length > 0 && edgeAhead)
      ? { word: "AHEAD ON EDGE · BEHIND ON SHAPE", col: "var(--goldBright)", bd: "rgba(240,192,80,0.35)", bg: "rgba(201,152,42,0.07)", why: `every ratio passes and your expectancy (${fmtEv(proj.evAct)}/trade) beats the design (${fmtEv(proj.evSim)}) — but ${tiersBehind.length} winner tier${tiersBehind.length === 1 ? " is" : "s are"} behind pace. The edge is being carried by a higher win rate and smaller losses, NOT the big winners the design counts on — it holds only while the win rate does. Land the tail to make it robust.` }
      : (tiersBehind.length === 0 && failList.length === 1)
        ? { word: "DRIFTING", col: "var(--goldBright)", bd: "rgba(240,192,80,0.35)", bg: "rgba(201,152,42,0.07)", why: "1 check failing: " + failList[0] }
        : { word: "OFF TRACK", col: "var(--red)", bd: "rgba(239,68,68,0.35)", bg: "rgba(239,68,68,0.07)", why: `${failList.length} of ${checksN} checks failing — ` + failList.join(" · ") };
  const GRID = "minmax(150px,1.5fr) minmax(120px,1fr) minmax(110px,1fr) 90px";
  const goDesign = () => { try { sessionStorage.setItem("viv-goto-sim", "1"); } catch { /* private mode */ } setPage && setPage("tools"); };
  // No design yet → the invitation, not an empty preset (member ask 2026-07-11)
  if (!pb.designed) return (
    <div className="card reveal" style={{ padding: "26px 24px", marginBottom: 18, textAlign: "center" }}>
      <div style={{ fontSize: "0.95rem", fontWeight: 800, color: "var(--goldBright)", marginBottom: 8 }}>Design your playbook to track your performance live</div>
      <div style={{ fontSize: "0.76rem", color: "var(--muted)", lineHeight: 1.7, maxWidth: 620, margin: "0 auto 14px" }}>
        Build your system in the Return Simulator — your win rate, average loss, winner sizes — then hit <b style={{ color: "var(--goldBright)" }}>💾 Save playbook design</b>.
        It becomes your benchmark here: one verdict, a design-vs-live scoreboard, and a winner ladder that checks the big winners are landing on schedule. The best feedback loop a trader can have.
      </div>
      <button className="distbtn on" onClick={goDesign}>✎ Design my playbook → Return Simulator</button>
    </div>
  );
  return (
    <div className="card reveal" style={{ padding: "16px 20px", marginBottom: 18 }}>
      <div style={{ display: "flex", alignItems: "center", flexWrap: "wrap", gap: 10, marginBottom: 12 }}>
        <input value={pb.name} onChange={e => setPb(p => ({ ...p, name: e.target.value }))} title="Name your playbook"
          style={{ background: "transparent", border: "1px solid rgba(255,255,255,0.12)", borderRadius: 8, color: "var(--goldBright)", fontWeight: 800, fontSize: "0.86rem", padding: "5px 10px", minWidth: 200 }} />
        <button className="distbtn" style={{ marginLeft: "auto" }} onClick={goDesign} title="Rework the design in the Return Simulator, then save — nothing here changes until you do">✎ Edit playbook design</button>
      </div>
      {/* ── ONE verdict — the whole card answered in a glance. The only loud colour on this card. ── */}
      <div style={{ display: "flex", alignItems: "baseline", flexWrap: "wrap", gap: "4px 12px", padding: "12px 16px", borderRadius: 12, background: verdict.bg, border: `1px solid ${verdict.bd}`, marginBottom: 12 }}>
        <b style={{ color: verdict.col, fontSize: "0.95rem", fontWeight: 800, letterSpacing: "0.04em", whiteSpace: "nowrap" }}>{verdict.word}</b>
        <span style={{ fontSize: "0.7rem", color: "var(--muted)", lineHeight: 1.5, flex: "1 1 220px", minWidth: 0 }}>{verdict.why}</span>
        <span style={{ fontSize: "0.64rem", color: "var(--muted)", whiteSpace: "nowrap" }}>{m.n} closed trade{m.n === 1 ? "" : "s"} in this view</span>
      </div>
      {/* Progress through the design's trade count */}
      {pace && (
        <div style={{ display: "flex", alignItems: "center", flexWrap: "wrap", gap: 10, margin: "0 2px 10px" }}>
          <span className="term" data-tip="Your playbook's math is defined over a total number of trades — the expectancy only shows up across the full count. This is how far through the design you are." style={{ fontSize: "0.74rem", fontWeight: 700 }}>
            Trades taken <b style={{ fontVariantNumeric: "tabular-nums" }}>{pace.taken.toLocaleString()} of {pace.total.toLocaleString()}</b>
          </span>
          <div style={{ flex: "1 1 140px", minWidth: 100, height: 5, borderRadius: 4, background: "rgba(255,255,255,0.07)", overflow: "hidden" }}>
            <div style={{ width: (pace.frac * 100).toFixed(1) + "%", height: "100%", background: "var(--gold)" }} />
          </div>
          <span style={{ fontSize: "0.68rem", color: "var(--muted)", fontVariantNumeric: "tabular-nums" }}>{pace.remaining.toLocaleString()} to go · {(pace.frac * 100).toFixed(0)}%</span>
        </div>
      )}
      {/* ── Scoreboard: design vs live. Numbers stay neutral — colour marks only the verdict. ── */}
      <div style={{ display: "grid", gridTemplateColumns: GRID, gap: "0 10px", alignItems: "center", padding: "2px 6px 6px", fontSize: "0.56rem", fontWeight: 800, letterSpacing: "0.1em", textTransform: "uppercase", color: "var(--muted)" }}>
        <span>Metric</span><span>Your design</span><span>Live</span><span style={{ textAlign: "right" }}>Verdict</span>
      </div>
      {ROWS.map(r => (
        <div key={r.k} style={{ display: "grid", gridTemplateColumns: GRID, gap: "2px 10px", alignItems: "center", padding: "9px 6px", borderTop: "1px solid rgba(255,255,255,0.05)", fontSize: "0.78rem", minWidth: 0 }}>
          <span className="term" data-tip={r.tip} style={{ fontWeight: 700, minWidth: 0, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{r.label}</span>
          <span style={{ color: "var(--muted)", fontVariantNumeric: "tabular-nums", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{r.design}</span>
          <b style={{ fontVariantNumeric: "tabular-nums", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{r.live ?? "—"}</b>
          <span style={{ textAlign: "right", fontWeight: 800, fontSize: "0.62rem", whiteSpace: "nowrap", color: r.ok == null ? "var(--muted)" : r.ok ? "var(--green)" : "var(--red)" }}>{r.ok == null ? "—" : r.ok ? "✓ PASS" : "✕ MISS"}</span>
        </div>
      ))}
      {/* ── Winner ladder — are the BIG winners landing on schedule? ── */}
      {pace && (
        <div style={{ marginTop: 12, border: "1px solid rgba(255,255,255,0.08)", borderRadius: 12, padding: "10px 14px", background: "rgba(255,255,255,0.015)" }}>
          <div style={{ fontSize: "0.58rem", fontWeight: 800, letterSpacing: "0.1em", textTransform: "uppercase", color: "var(--gold)", marginBottom: 2 }}>Winner ladder — are the big ones landing on schedule?</div>
          {pace.tiers.map((tr, i) => {
            const due = tr.expectedNow; // unrounded — "0.5 due" is real information, never floored to 0
            return (
              <div key={i} style={{ display: "grid", gridTemplateColumns: GRID, gap: "2px 10px", alignItems: "center", padding: "8px 0", borderTop: i ? "1px solid rgba(255,255,255,0.05)" : "none", fontSize: "0.76rem", minWidth: 0 }}>
                <span className="term" data-tip={`The design plans ${tr.planned} winners of +${tr.gain}${pace.suffix} or larger across the full ${pace.total.toLocaleString()}-trade cycle. "Due by now" pro-rates that to your ${pace.taken.toLocaleString()} trades so far — a playbook dies silently when the big tiers stop landing while every ratio still looks fine.`} style={{ fontWeight: 700, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>+{tr.gain}{pace.suffix}+ winners</span>
                <span style={{ color: "var(--muted)", fontVariantNumeric: "tabular-nums", whiteSpace: "nowrap" }}>{tr.planned} planned · {due < 10 ? due.toFixed(1) : Math.round(due)} due by now</span>
                <b style={{ fontVariantNumeric: "tabular-nums" }}>{tr.actual} landed</b>
                <span style={{ textAlign: "right", fontWeight: 800, fontSize: "0.62rem", whiteSpace: "nowrap", color: tr.ok ? "var(--green)" : "var(--red)" }}>{tr.ok ? "✓ ON PACE" : `✕ NEED ${Math.max(1, Math.ceil(due - tr.actual))} MORE`}</span>
              </div>
            );
          })}
          {uR && m.noR > 0 && <div style={{ fontSize: "0.62rem", color: "var(--muted)", marginTop: 6 }}>{m.noR} trade{m.noR === 1 ? "" : "s"} without a recorded R (no original stop) excluded from R-based rows — never guessed.</div>}
          <div style={{ fontSize: "0.62rem", color: "var(--muted)", marginTop: 8, lineHeight: 1.5 }}>Every ratio above can pass while the design still fails — if the big winners aren't landing at pace, the expectancy math never materializes. This ladder is the honest check.</div>
        </div>
      )}
      {!pace && <div style={{ fontSize: "0.66rem", color: "var(--muted)", marginTop: 10, lineHeight: 1.5 }}>Re-save your design in the Return Simulator to unlock trade-count and winner-ladder pacing — older saves stored only the ratio targets.</div>}
      <div style={{ display: "flex", alignItems: "center", gap: 10, marginTop: 10 }}>
        <div style={{ fontSize: "0.66rem", color: "var(--muted)", lineHeight: 1.5, flex: 1 }}>Verdicts recompute from the same trades this page shows — use the date filter to score a specific period. Targets come from your saved design; change them in the Return Simulator.</div>
        <button className="distbtn" onClick={() => setMore(o => !o)}>{more ? "Hide projection ▴" : "Projection ▾"}</button>
      </div>
      {more && (
        <div style={{ marginTop: 12, borderTop: "1px solid rgba(255,255,255,0.06)", paddingTop: 12 }}>
          <div style={{ display: "flex", alignItems: "center", flexWrap: "wrap", gap: "6px 18px", fontSize: "0.74rem" }}>
            <span className="term" data-tip={proj.unitR ? "Expectancy in R: the average R you'd make per trade — win-rate × avg win(R) − loss-rate × avg loss(R)." : "Expectancy: the average % you'd make per trade — win-rate × avg win − loss-rate × avg loss."} style={{ color: "var(--muted)" }}>Expectancy / trade</span>
            <span style={{ whiteSpace: "nowrap" }}>design <b style={{ fontVariantNumeric: "tabular-nums" }}>{proj.evSim == null ? "—" : (proj.evSim >= 0 ? "+" : "") + proj.evSim.toFixed(2) + proj.suffix}</b></span>
            <span style={{ whiteSpace: "nowrap" }}>you <b style={{ fontVariantNumeric: "tabular-nums" }}>{proj.evAct == null ? "—" : (proj.evAct >= 0 ? "+" : "") + proj.evAct.toFixed(2) + proj.suffix}</b></span>
            <span style={{ display: "inline-flex", alignItems: "center", gap: 6, color: "var(--muted)", fontSize: "0.68rem", whiteSpace: "nowrap" }}>
              at <input type="number" min={proj.unitR ? 0.1 : 1} max="100" step={proj.unitR ? 0.1 : 1} value={pb.simSize ?? (proj.unitR ? 0.5 : 15)} onChange={e => setPb(p => ({ ...p, simSize: e.target.value === "" ? "" : Number(e.target.value) }))}
                style={{ width: 56, background: "rgba(255,255,255,0.04)", border: "1px solid rgba(255,255,255,0.12)", borderRadius: 7, color: "var(--text)", padding: "3px 8px", fontSize: "0.7rem" }} /> {proj.sizeLabel}
            </span>
            {proj.evSim != null && proj.evAct != null && (
              <b style={{ marginLeft: "auto", fontSize: "0.7rem", color: proj.evAct >= proj.evSim ? "var(--green)" : "var(--red)" }}>
                {proj.evAct >= proj.evSim ? (tiersBehind.length ? "ahead on edge — shape behind (see ladder)" : "trading ahead of the design") : `lagging the design by ${(proj.evSim - proj.evAct).toFixed(2)}${proj.suffix}/trade`}
              </b>
            )}
          </div>
          {/* Projected equity — SIMULATED trade-by-trade from the design's REAL mix (losses,
              small wins, the occasional homer), not smooth compounding: a straight "average" line
              hides the drawdowns the design actually implies (Valen 2026-07-12). Seeded PRNG keeps
              the chart stable between renders; ↻ rolls another equally-likely future. INTERACTIVE:
              glide/drag across the chart to read both curves at any trade. */}
          {proj.evSim != null && proj.evAct != null && (() => {
            const N = 100, sz = proj.size / 100;
            const gPer = (r) => 1 + sz * (proj.unitR ? r : r / 100); // one trade's equity multiplier
            const mulberry = (seed) => () => { seed |= 0; seed = (seed + 0x6D2B79F5) | 0; let t = Math.imul(seed ^ (seed >>> 15), 1 | seed); t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t; return ((t ^ (t >>> 14)) >>> 0) / 4294967296; };
            // DESIGN pool = the saved design's exact outcomes: each tier's winners at their gain,
            // leftover (sub-tier) winners at half the smallest gain, losers at −avg loss.
            const dz = pb.design || {};
            const dTiers = (dz.tiers || []).filter(t => t.gain > 0 && t.count > 0);
            const tierWins = dTiers.reduce((s, t) => s + t.count, 0);
            const designPool = [];
            dTiers.forEach(t => { for (let i = 0; i < t.count; i++) designPool.push(t.gain); });
            const smallW = Math.max(0, (dz.winners || 0) - tierWins);
            const smallG = dTiers.length ? Math.min(...dTiers.map(t => t.gain)) / 2 : 1;
            for (let i = 0; i < smallW; i++) designPool.push(smallG);
            for (let i = 0; i < (dz.losers || 0); i++) designPool.push(-(Number(tg.avgLoss) || 0));
            // YOUR pool = your actual recorded outcomes in the design's own unit
            const actPool = proj.unitR
              ? [...m.winRs, ...(m.lossRs || []).map(v => -v)]
              : [...m.winPcts, ...(m.lossPcts || []).map(v => -v)];
            const walk = (pool, seed) => { const r = mulberry(seed); let eq = 1; const out = [1]; for (let i = 0; i < N; i++) { eq *= gPer(pool[Math.floor(r() * pool.length)]); out.push(eq); } return out; };
            const smoothOf = (ev) => Array.from({ length: N + 1 }, (_, i) => Math.pow(gPer(ev), i)); // fallback for old saves without structure
            // Dispersion band: 120 design runs → P10–P90 envelope + median endpoint (what "on
            // design" REALLY spans — the design is a distribution, not one line).
            const RUNS = 120;
            const paths = designPool.length ? Array.from({ length: RUNS }, (_, k) => walk(designPool, roll * 7919 + k * 104729 + 1)) : null;
            const band = paths ? Array.from({ length: N + 1 }, (_, i) => { const col = paths.map(p => p[i]).sort((a, b) => a - b); return [col[Math.floor(RUNS * 0.1)], col[Math.floor(RUNS * 0.9)]]; }) : null;
            const finals = paths ? paths.map(p => p[N]).sort((a, b) => a - b) : null;
            const medSim = finals ? finals[Math.floor(RUNS / 2)] : proj.multSim;
            const simC = paths ? paths[roll % RUNS] : smoothOf(proj.evSim);
            const actC = actPool.length ? walk(actPool, roll * 15485863 + 7) : smoothOf(proj.evAct);
            const all = [...simC, ...actC, ...(band ? band.flat() : [])]; const lo = Math.min(...all); const hiR = Math.max(...all); const hi = hiR === lo ? lo + 1 : hiR;
            const X = (i) => (i / N) * 600, Y = (v) => 10 + (1 - (v - lo) / (hi - lo)) * 158;
            const path = (arr) => "M" + arr.map((v, i) => `${X(i).toFixed(1)},${Y(v).toFixed(1)}`).join(" L");
            const h = hov == null ? null : Math.min(N, Math.max(0, hov));
            return (
              <div style={{ marginTop: 12 }}>
                <div style={{ display: "flex", alignItems: "baseline", flexWrap: "wrap", gap: "2px 12px", marginBottom: 6 }}>
                  <span style={{ fontSize: "0.58rem", fontWeight: 800, letterSpacing: "0.1em", textTransform: "uppercase", color: "var(--muted)" }}>Projected equity — next 100 trades, simulated</span>
                  <span style={{ fontSize: "0.7rem", color: h == null ? "var(--muted)" : "var(--text)", fontVariantNumeric: "tabular-nums" }}>
                    {h == null ? "glide across the chart to inspect any trade" : <>trade {h} · design <b style={{ color: "var(--goldBright)" }}>×{simC[h].toFixed(3)}</b> · you <b>×{actC[h].toFixed(3)}</b> · gap <b style={{ color: actC[h] >= simC[h] ? "var(--green)" : "var(--red)" }}>{(actC[h] - simC[h] >= 0 ? "+" : "") + (actC[h] - simC[h]).toFixed(3)}</b></>}
                  </span>
                  {paths && <button className="distbtn" style={{ marginLeft: "auto", fontSize: "0.62rem", padding: "3px 10px" }} onClick={() => setRoll(r => r + 1)} title="Both lines are ONE possible future drawn from the trade mix — roll the dice again to see another equally-likely path">↻ another future</button>}
                </div>
                <div style={{ border: "1px solid rgba(255,255,255,0.08)", borderRadius: 12, padding: "8px 10px", background: "rgba(255,255,255,0.015)", touchAction: "none", cursor: "crosshair" }}
                  onPointerMove={e => { const r = e.currentTarget.getBoundingClientRect(); const f = Math.min(1, Math.max(0, (e.clientX - r.left - 10) / Math.max(1, r.width - 20))); setHov(Math.round(f * N)); }}
                  onPointerLeave={() => setHov(null)}>
                  <svg viewBox="0 0 600 180" style={{ width: "100%", height: 160, display: "block" }} preserveAspectRatio="none" role="img" aria-label="Designed vs actual projected equity">
                    <line x1="0" y1={Y(1).toFixed(1)} x2="600" y2={Y(1).toFixed(1)} stroke="rgba(255,255,255,0.08)" strokeWidth="1" />
                    {band && <path d={"M" + band.map((b, i) => `${X(i).toFixed(1)},${Y(b[1]).toFixed(1)}`).join(" L") + " L" + band.slice().reverse().map((b, i) => `${X(N - i).toFixed(1)},${Y(b[0]).toFixed(1)}`).join(" L") + " Z"} fill="rgba(201,152,42,0.08)" stroke="none" />}
                    <path d={path(simC)} fill="none" stroke="var(--goldBright)" strokeWidth="2" vectorEffect="non-scaling-stroke" />
                    <path d={path(actC)} fill="none" stroke="rgba(255,255,255,0.55)" strokeWidth="2" strokeDasharray="5 3" vectorEffect="non-scaling-stroke" />
                    {h != null && (<>
                      <line x1={X(h).toFixed(1)} y1="0" x2={X(h).toFixed(1)} y2="180" stroke="rgba(255,255,255,0.22)" strokeWidth="1" vectorEffect="non-scaling-stroke" />
                      <circle cx={X(h).toFixed(1)} cy={Y(simC[h]).toFixed(1)} r="3.5" fill="var(--goldBright)" />
                      <circle cx={X(h).toFixed(1)} cy={Y(actC[h]).toFixed(1)} r="3.5" fill="#ffffff" />
                    </>)}
                  </svg>
                </div>
                <div style={{ display: "flex", gap: 16, flexWrap: "wrap", fontSize: "0.64rem", color: "var(--muted)", marginTop: 6 }}>
                  <span className="term" data-tip={paths ? "One simulated run of the design's exact trade mix — its losses, small wins and homers in random order. The jagged dips are REAL: they're the drawdowns your design implies even when it works." : "Smooth expectancy compounding (re-save your design in the simulator to unlock the trade-mix simulation)."}><i style={{ display: "inline-block", width: 12, height: 2, background: "var(--goldBright)", verticalAlign: "middle", marginRight: 5 }} />the design, one run of {N} trades → <b style={{ color: "var(--goldBright)" }}>×{simC[N].toFixed(2)}</b></span>
                  {paths && <span className="term" data-tip="120 simulated runs of the same design — 80% of futures end inside this band. Judge yourself against the BAND, not one line."><i style={{ display: "inline-block", width: 12, height: 8, background: "rgba(201,152,42,0.25)", verticalAlign: "middle", marginRight: 5 }} />80% of design futures → median <b style={{ color: "var(--goldBright)" }}>×{medSim.toFixed(2)}</b>, band ×{finals[Math.floor(RUNS * 0.1)].toFixed(2)}–×{finals[Math.floor(RUNS * 0.9)].toFixed(2)}</span>}
                  <span className="term" data-tip="The same 100 trades drawn from YOUR actual recorded outcomes instead of the design's — what continuing to trade exactly as you have would look like."><i style={{ display: "inline-block", width: 12, height: 2, background: "rgba(255,255,255,0.55)", verticalAlign: "middle", marginRight: 5 }} />your actual trade mix, one run → <b>×{actC[N].toFixed(2)}</b></span>
                </div>
              </div>
            );
          })()}
        </div>
      )}
    </div>
  );
}

