  const [edgeMatrixView, setEdgeMatrixView] = useState("table"); // 3-D edge matrix presentation: "table" (DEFAULT — Valen) | "heatmap"
  const [tgts, setTgts] = useState(loadTargets); // TradeZella-style planning targets per trade id
